import{_ as s,o as i,c as a,ag as t}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"Inside Claude Code: Retrieval Strategy","description":"Claude Code skips RAG entirely, letting the agent grep and a small metadata index handle retrieval.","frontmatter":{"description":"Claude Code skips RAG entirely, letting the agent grep and a small metadata index handle retrieval.","date":"2026-04-11","tags":["Claude Code","Retrieval"]},"headers":[],"relativePath":"blog/inside-claude-code/retrieval-strategy.md","filePath":"en/blog/inside-claude-code/retrieval-strategy.md","lastUpdated":1780484238000}'),n={name:"blog/inside-claude-code/retrieval-strategy.md"};function h(r,e,l,d,o,p){return i(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="inside-claude-code-retrieval-strategy" tabindex="-1">Inside Claude Code: Retrieval Strategy <a class="header-anchor" href="#inside-claude-code-retrieval-strategy" aria-label="Permalink to &quot;Inside Claude Code: Retrieval Strategy&quot;">​</a></h1><p>The model has no memory of your codebase. Every time it runs, it starts from zero. So it needs a way to &quot;see&quot; the right code and context before it can do anything useful.</p><p>The standard industry answer to this is RAG: embed your project data into a vector database, retrieve semantically similar chunks at query time, inject them into the prompt, done.</p><p>Claude Code doesn&#39;t do this.</p><h2 id="what-it-does-instead" tabindex="-1">What it does instead <a class="header-anchor" href="#what-it-does-instead" aria-label="Permalink to &quot;What it does instead&quot;">​</a></h2><p>The retrieval architecture has three layers.</p><p><strong>Layer 1: Metadata scan.</strong> When the model needs to recall a memory, <code>memoryScan.ts</code> reads only the frontmatter header of every <code>.md</code> file in the memory directory, the first 30 lines, just the name, description, type, and timestamp. It assembles a compact manifest that looks something like this:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code" tabindex="0"><code><span class="line"><span>- [feedback] feedback_testing.md (2025-04-10T...): integration tests must hit a real db, not mocks</span></span>\n<span class="line"><span>- [user] user_role.md (2025-04-08T...): user is a senior Go engineer, new to the React side</span></span></code></pre></div><p>Fast, cheap, no inference needed.</p><p><strong>Layer 2: LLM sidecar call.</strong> <code>findRelevantMemories.ts</code> sends this manifest to a lightweight Claude Sonnet call made outside the main conversation context. Sonnet reads the manifest and returns a JSON list of at most five filenames worth reading in full. The selection prompt is deliberately conservative: &quot;If you are unsure if a memory will be useful in processing the user&#39;s query, then do not include it in your list. Be selective and discerning.&quot; Only those files get surfaced to the main model.</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#AB5959;--shiki-dark:#CB7676;">const </span><span style="--shiki-light:#B07D48;--shiki-dark:#BD976A;">result</span><span style="--shiki-light:#999999;--shiki-dark:#666666;"> =</span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;"> await</span><span style="--shiki-light:#59873A;--shiki-dark:#80A665;"> sideQuery</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">({</span></span>\n<span class="line"><span style="--shiki-light:#998418;--shiki-dark:#B8A965;">  model</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">: </span><span style="--shiki-light:#59873A;--shiki-dark:#80A665;">getDefaultSonnetModel</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">(),</span></span>\n<span class="line"><span style="--shiki-light:#998418;--shiki-dark:#B8A965;">  system</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">: </span><span style="--shiki-light:#B07D48;--shiki-dark:#BD976A;">SELECT_MEMORIES_SYSTEM_PROMPT</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">,</span></span>\n<span class="line"><span style="--shiki-light:#998418;--shiki-dark:#B8A965;">  messages</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">: [{ </span><span style="--shiki-light:#998418;--shiki-dark:#B8A965;">role</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">: </span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">user</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">, </span><span style="--shiki-light:#998418;--shiki-dark:#B8A965;">content</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">: </span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">`</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">Query: </span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">${</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">query</span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">}</span><span style="--shiki-light:#A65E2B;--shiki-dark:#C99076;">\\n\\n</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">Available memories:</span><span style="--shiki-light:#A65E2B;--shiki-dark:#C99076;">\\n</span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">${</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">manifest</span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">}</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">`</span><span style="--shiki-light:#999999;--shiki-dark:#666666;"> }],</span></span>\n<span class="line"><span style="--shiki-light:#998418;--shiki-dark:#B8A965;">  max_tokens</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">: </span><span style="--shiki-light:#2F798A;--shiki-dark:#4C9A91;">256</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">,</span></span>\n<span class="line"><span style="--shiki-light:#998418;--shiki-dark:#B8A965;">  output_format</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">: { </span><span style="--shiki-light:#998418;--shiki-dark:#B8A965;">type</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">: </span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">json_schema</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">&#39;</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">, ... },</span></span>\n<span class="line"><span style="--shiki-light:#998418;--shiki-dark:#B8A965;">  skipSystemPromptPrefix</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">: </span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">true</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">,</span></span>\n<span class="line"><span style="--shiki-light:#999999;--shiki-dark:#666666;">})</span></span></code></pre></div><p>No embeddings. No cosine similarity. It&#39;s more like a card catalog: scan the index cards, let a smart librarian decide which books to pull, then read those books in full.</p><p><strong>Layer 3: Self-directed grep.</strong> For deeper searches through transcript history, the model is handed grep instructions directly and runs the search itself:</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#AB5959;--shiki-dark:#CB7676;">const </span><span style="--shiki-light:#B07D48;--shiki-dark:#BD976A;">memSearch</span><span style="--shiki-light:#999999;--shiki-dark:#666666;"> =</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;"> `</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">grep -rn &quot;&lt;search term&gt;&quot; </span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">${</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">autoMemDir</span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">}</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;"> --include=&quot;*.md&quot;</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">`</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">;</span></span>\n<span class="line"><span style="--shiki-light:#AB5959;--shiki-dark:#CB7676;">const </span><span style="--shiki-light:#B07D48;--shiki-dark:#BD976A;">transcriptSearch</span><span style="--shiki-light:#999999;--shiki-dark:#666666;"> =</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;"> `</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">grep -rn &quot;&lt;search term&gt;&quot; </span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">${</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">projectDir</span><span style="--shiki-light:#1E754F;--shiki-dark:#4D9375;">}</span><span style="--shiki-light:#B56959;--shiki-dark:#C98A7D;">/ --include=&quot;*.jsonl&quot;</span><span style="--shiki-light:#B5695977;--shiki-dark:#C98A7D77;">`</span><span style="--shiki-light:#999999;--shiki-dark:#666666;">;</span></span></code></pre></div><p>The &quot;last resort&quot; comment in the code is telling. Transcript files are large, full <code>.jsonl</code> conversation logs, slow to scan. They&#39;re only reached when the memory layer doesn&#39;t have what&#39;s needed. Under the hood &quot;grep&quot; is actually ripgrep, a Rust-based tool that ships bundled with Claude Code in three fallback modes: system <code>rg</code> binary if one exists, a vendored platform-specific binary, or embedded directly into the Bun executable. The timeout handling is worth noting: in the embedded (spawn) path, SIGTERM fires at the timeout with SIGKILL escalating 5 seconds later; in the non-embedded (execFile) path, SIGKILL fires directly. Either way, this is load-bearing infrastructure, not a prototype.</p><p>It&#39;s also worth noting that the grep command strings above are specific to embedded/REPL mode. In non-embedded mode, the model is given a structured <code>${GREP_TOOL_NAME}</code> tool call with <code>pattern=...</code> format instead. Same idea, different interface.</p><h2 id="why-this-beats-rag" tabindex="-1">Why this beats RAG <a class="header-anchor" href="#why-this-beats-rag" aria-label="Permalink to &quot;Why this beats RAG&quot;">​</a></h2><p>Claude Code&#39;s bet is that agentic search beats RAG: when the agent decides what to search for and how to narrow it, the results are far more relevant than pre-packaged chunks.</p><p>The analogy that makes sense to me: RAG is like pre-packaging all the relevant material for an intern before they start work. Agentic search is giving them direct access to the entire document library and letting them dig. The stronger the model, the bigger the advantage for the latter, because the model knows better than you do what information it actually needs.</p><p>There&#39;s also a more subtle design insight here. In RAG, index quality depends on the embedding model at write time and vector similarity at read time. You have limited control over what gets retrieved, and index staleness is a constant maintenance problem.</p><p>In Claude Code&#39;s approach, index quality depends on how well the model wrote the memory description at save time. That&#39;s a compression problem models are already good at. As models improve at writing concise, accurate descriptions, retrieval quality improves for free, no reindexing required.</p><p>The engineering payoff: no embedding pipeline to maintain, no vector database to operate, no index staleness to manage. The cost is one small sidecar API call per context switch. Given the accuracy difference and the maintenance burden avoided, that&#39;s a good trade.</p><h2 id="the-takeaway" tabindex="-1">The Takeaway <a class="header-anchor" href="#the-takeaway" aria-label="Permalink to &quot;The Takeaway&quot;">​</a></h2><p>What this really illustrates is how the boundary between &quot;what the engineering system handles&quot; and &quot;what the model handles&quot; keeps shifting as models get stronger.</p><p>A lot of things that used to require complex retrieval pipelines, semantic indexing, chunking strategies, similarity tuning, are increasingly just better left to the agent. The model can read an index card manifest and pick the right five files to read. It can write its own grep queries against a transcript store. It can do these things more accurately than a static pipeline can.</p><p>The engineering complexity that used to live in your RAG stack gets replaced by a cheap inference call and some well-structured metadata. That&#39;s a pretty good deal.</p>',26)])])}const g=s(n,[["render",h]]);export{c as __pageData,g as default};
